    def _sort_palette(self, sort_palette):
        palette_mode = self.palette.mode
        nchannels = len(palette_mode)
        palette = self.palette.palette
        colors = [
            tuple(palette[i : i + nchannels])
            for i in range(0, len(palette), nchannels)
        ]

        if callable(sort_palette):
            key = sort_palette
        elif sort_palette == "rgb":

            def key(color):
                return color[:3]

        elif sort_palette == "luminance":

            def key(color):
                return color[0] * 299 + color[1] * 587 + color[2] * 114

        else:
            raise ValueError(
                "sort_palette must be 'rgb', 'luminance', or a callable"
            )

        order = sorted(range(len(colors)), key=lambda i: key(colors[i]))

        lut = [0] * 256
        for new_index, old_index in enumerate(order):
            lut[old_index] = new_index

        im = self.point(lut)

        from . import ImagePalette

        new_palette = bytearray()
        for old_index in order:
            new_palette += bytes(colors[old_index])
        im.palette = ImagePalette.ImagePalette(palette_mode, bytes(new_palette))

        return im"}

